import{_ as e,o as r,c as o,a7 as a}from"./chunks/framework.BgApuQ2e.js";const n="/images/combined-wealth-world/naked1.png",p="/images/combined-wealth-world/money-pile.png",l="/images/combined-wealth-world/bills-to-moon.png",s="/images/combined-wealth-world/bills-to-moon-2-1024x658.png",i="/images/combined-wealth-world/vermont-1024x817.jpg",g="/images/combined-wealth-world/algeria-1024x789.jpg",h="/images/combined-wealth-world/mined-cube-pyramid.jpg",c="/images/combined-wealth-world/big-cube-pyramid.jpg",w="/images/combined-wealth-world/56000.png",m="/images/combined-wealth-world/1-percent.png",d="/images/combined-wealth-world/10-percent.png",b="/images/combined-wealth-world/billionaires-come-out1.png",u="/images/combined-wealth-world/billionaires-in-a-line.png",_="/images/combined-wealth-world/ortega.png",f="/images/combined-wealth-world/10x10-grid.png",y="/images/combined-wealth-world/jellybean-boxes1.png",k="/images/combined-wealth-world/jellybean-boxes-2.png",j="/images/combined-wealth-world/zuck-hoodie.png",W="/images/combined-wealth-world/zuck-wealth.png",v="/images/combined-wealth-world/arod-wealth.png",A="/images/combined-wealth-world/lawyer-wealth.png",x="/images/combined-wealth-world/average-american.png",z="/images/combined-wealth-world/average-human.png",P="/images/combined-wealth-world/hungry.png",T="/images/combined-wealth-world/hungry-2.png",B="/images/combined-wealth-world/potato-from-sky-1024x560.jpg",C="/images/combined-wealth-world/potato-ground-1.png",S="/images/combined-wealth-world/potato-ground-2.png",q="/images/combined-wealth-world/pizza-niger-1024x617.jpg",$="/images/combined-wealth-world/pizza-ground.png",D="/images/combined-wealth-world/poland-spring-1024x789.jpg",R="/images/combined-wealth-world/Winston.jpg",I="/images/combined-wealth-world/pinit_fg_en_rect_gray_20.png",O=JSON.parse('{"title":"What Could You Buy With $241 Trillion?","description":"","frontmatter":{"title":"What Could You Buy With $241 Trillion?","titleZh":"241万亿美元能买什么","date":"2014-03-25T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/03/combined-wealth-world.html","slug":"combined-wealth-world"},"headers":[],"relativePath":"posts/combined-wealth-world.md","filePath":"posts/combined-wealth-world.md","lastUpdated":1782886257000}'),Z={name:"posts/combined-wealth-world.md"};function E(F,t,N,U,Y,M){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="_241万亿美元能买什么-·-what-could-you-buy-with-241-trillion" tabindex="-1">241万亿美元能买什么 · What Could You Buy With $241 Trillion? <a class="header-anchor" href="#_241万亿美元能买什么-·-what-could-you-buy-with-241-trillion" aria-label="Permalink to &quot;241万亿美元能买什么 · What Could You Buy With $241 Trillion?&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/03/combined-wealth-world.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/03/combined-wealth-world.html</a> · 2014-03-25</p></blockquote><p>如果你把自己拥有的一切都卖掉,把所有投资变现,还清所有债务,再把银行账户里的现金全都取出来,会发生什么?</p><p>你会光着身子站在街上,无处可去,手里攥着一堆现金,大家都盯着你看。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/naked1.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="holding all your net worth"></a></p><p>而你手里握着的那堆现金,就是你的净资产。</p><p>好,现在想象一下,世界上其他所有人也都这么干(就当这事儿说得通吧),然后全世界的人,光着身子、抱着自己的全部财富,聚到一起,把各自的钱统统扔到一个大堆里。这堆钱一共会有多少?</p><p>241,000,000,000,000 美元。</p><p>全世界所有人加起来的财富是 241 万亿美元。1</p><p>所以此刻,全人类会一起光溜溜地站在那儿,一个个身无分文,望着一座巨大的钞票山。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/money-pile.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="The world&#39;s wealth in hundreds"></a></strong></p><p>好吧,我们现在这局面有点怪。先来把这堆钱整理一下,全部换成 100 美元一张的钞票,叠成一大摞。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/bills-to-moon.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="stack of bills to the moon"></a></p><p>100 张 100 美元钞票(1 万美元)摞起来是 1.09 厘米厚,所以 100 万美元摞起来就是 1 米出头,10 亿美元是 1 公里多一点,而 241 万亿美元摞起来高达 262,000 公里,已经走完了地球到月球 68% 的路程。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/bills-to-moon-2.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Bills to the moon"></a></strong></p><p>现在我们把这些钞票全都摊到地上,铺成一层。一张钞票的面积是 103 平方厘米,所以 2.41 万亿张差不多能盖住整个佛蒙特州。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/vermont.jpg" target="_blank" rel="noreferrer"><img src="'+i+'" alt="All world&#39;s wealth covering vermont"></a></strong></p><p>要是全换成 1 美元一张的呢?241 万亿张 1 美元钞票足够盖住整个阿尔及利亚。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/algeria.jpg" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Algeria covered in $1 Bills"></a></strong></p><p>好,钞票玩够了。来试试黄金。如果把人类历史上开采出来的所有黄金全部熔成一个立方体,它的边长是 20.7 米(价值 8.6 万亿美元)。2</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/mined-cube-pyramid.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt="All the gold ever mined"></a></p><p>比想象的要小得多,对吧?那如果有足够的黄金能代表全世界 241 万亿美元的所有财富,这个金立方体又会有多大?</p><p>它的边长大约是 63 米。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/big-cube-pyramid.jpg" target="_blank" rel="noreferrer"><img src="'+c+'" alt="All the world&#39;s wealth in gold"></a></strong></p><p>好,那个立方体就是我们要处理的东西。如果全世界的财富完全平均分配,每个成年人拿一份,每个人就能分到 51,600 美元,也就是这么多黄金:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/56000.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="If wealth were divided evenly"></a></strong></p><p>但财富并没有被平均分配。我们来看看全世界最富的 1% 人口 和其余 99% 人口 各自拥有多少?</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/1-percent.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="1 percent guy has 46% of wealth"></a></strong></p><p>那前 10% 呢?</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/10-percent.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="10 percent of people have 86 percent of wealth"></a></strong></p><p>为了进一步说明财富分配到底有多不均,咱们把世界上最富的几个亿万富翁请出来。3</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/billionaires-come-out1.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="billionaires come out"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/billionaires-in-a-line.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="World&#39;s richest people"></a></p><p>Amancio Ortega 是谁啊?我不认识你,请你离开。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/ortega.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="Sad Ortega"></a></strong></p><p>瑞士信贷 (Credit Suisse) 最近发布了<a href="https://publications.credit-suisse.com/tasks/render/file/?fileID=BCDB1364-A105-0560-1332EC9100FF5C83" target="_blank" rel="noreferrer">一份报告</a>,揭示出人类中较穷的那一半——35 亿人——所拥有的财富不到全球总财富的 1%。而从顶端开始算,只需要最富的 85 个人的财富加起来,就等于最底层 35 亿人的财富。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/10x10-grid.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="World&#39;s richest and poorest"></a></strong></p><p>换个角度感受一下,85 人是全世界人口的 1/8400 万。所以如果一颗软糖代表 85 个人,整个人类就可以用 8400 万颗软糖来表示,大约能装满两个 5 米高的立方体:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/jellybean-boxes1.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="The richest 85 people"></a></p><p>于是,富人那一半的盒子里最富的那颗软糖,拥有的财富就等于<em>穷人那一半整个盒子加起来的财富:</em></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/jellybean-boxes-2.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="Richest jellybean"></a></strong></p><p>为了更进一步了解这85个人拥有的是什么级别的财富,我们来看看马克·扎克伯格 (Mark Zuckerberg),他是构成&quot;最富有的那颗软糖豆&quot;的这85人中最年轻的一位。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/zuck-hoodie.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt="Mark Zuckerberg"></a></strong></p><p>马克身家大约300亿美元。1074立方厘米的黄金约值100万美元。这么多黄金可以铸成一枚直径26厘米(约一英尺)、厚2厘米(约一英寸)的大金币。马克·扎克伯格的300亿美元可以换成3万枚这样的百万美元金币:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/zuck-wealth.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt="Mark Zuckerberg&#39;s Wealth"></a></strong></p><p>为了帮助我们理解这是多少钱,想想这个:世界最高建筑<a href="http://dubaidhow.com/blog/wp-content/uploads/2013/10/khalifa.jpg" target="_blank" rel="noreferrer">哈利法塔 (Burj Khalifa)</a>,造价15亿美元。这就是马克·扎克伯格每年靠财富利息赚到的钱(假设利率5%)——足够每年新建一座哈利法塔,而完全不影响他的财富本金。</p><p>另一种理解方式,是搞清楚一个亿万富翁比一个百万富翁富多少倍。为了说明这一点,我们把亚历克斯·罗德里格斯 (Alex Rodriguez) 拉进来讨论,他身家3亿美元——和最富有的影星差不多是一个级别。而A-Rod的财富只相当于马克·扎克伯格的1%。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/arod-wealth.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="A-Rod vs Zuckerberg"></a></p><p>那再往下,来看看最富有的1%人群里靠底层的——一个普通的百万富翁怎么样?一个有钱的律师可能有300万美元的净资产,这是A-Rod的1%。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/lawyer-wealth.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt="A-Rod&#39;s Wealth"></a></strong><br> 按几乎任何人的标准这位律师都是富人,但和A-Rod(1/100)、马克·扎克伯格(1/10000)相比,他<em>啥都不是</em>。可是,因为他既属于全世界最富的1%,也属于美国最富的1%5,我们照样把这三个人归在&quot;1%&quot;这一类里。把扎克伯格和这位律师归为一类,就跟把这位律师和一个身家只有他1/10000的人——一个全部家当只有300美元的高中生——归为一类一样离谱。</p><p>聊完这些&quot;百分之一&quot;,我们再拉一个普通美国人进来。事实上,不是随便一个,而是<em>那个</em>最普通的美国人——净资产刚好等于中位数、44,911美元的那位。1</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/average-american.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt="average american wealth"></a></p><p>虽然美国的<strong>平均 (mean)</strong> 净收入 301,140 美元1 是全球最高之一,但美国的<strong>中位数 (median)</strong> 净收入要低得多,在全球只排第 27 位。说 301,140 美元这个平均数代表美国人的平均净资产,那就错了——那只是如果把全美所有财富平均分给每个人后,每人能拿到多少。举个例子,在一个 10 人的国家里,如果 9 个人的净资产都在 3 万美元左右,而第 10 个人身价 1000 万美元,那么平均值(102.7 万美元)会让人以为普通人是百万富翁。而中位数大约是 3 万美元,才更能准确反映普通人的真实状况。</p><p>同理,上面那位拥有美国中位数净资产的普通美国人,意味着一半美国人比他富,一半比他穷。他就是那个平均美国人,净资产不到 45,000 美元,过得还不如另外 26 个国家的平均水平,包括希腊、斯洛文尼亚这些不算特别富裕的国家。1 美国的平均财富/中位数财富比值是 6.7,是世界上最高的比值之一,说明美国的财富不平等程度尤其严重。</p><p>那么普通<strong>人类</strong>呢?全世界成年人的中位数财富是多少?</p><p>大约 4,000 美元。1</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/average-human.png" target="_blank" rel="noreferrer"><img src="'+z+'" alt="average human wealth"></a></strong></p><p>就算按较穷国家的生活成本调整,这也相当低了。而且这还是<strong>中位数</strong>,意思是<strong>全世界一半的成年人</strong>名下财产不到 4,000 美元。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hungry.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt="hungry"></a></strong></p><p>好的。有什么问题吗?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/hungry-2.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt="hungry 2"></a></p><p>好吧,是有点烦人,不过也算合理。那我们把黄金换成一个等值的大土豆来解决这个问题。</p><p>用全世界的财富能买多大的土豆?一个普通土豆在美国卖 0.33 美元,大约 15 立方英寸,也就是 246 立方厘米,那么 241 万亿美元可以买到 179 立方公里的土豆,也就是一个大约 60 公里长的土豆。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/potato-from-sky.jpg" target="_blank" rel="noreferrer"><img src="'+B+'" alt="the world&#39;s wealth as a potato"></a></p><p>请享用!</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/potato-ground-1.png" target="_blank" rel="noreferrer"><img src="'+C+'" alt="huge potato 1"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/potato-ground-2.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="huge potato 2"></a></p><p>真是不懂感恩。</p><p>行吧。241 万亿美元能买多大一块披萨?</p><p>一张达美乐 (Domino&#39;s) 14 英寸披萨卖 19 美元(至少在纽约是这个价),算下来每美元 52.3 平方厘米。按这个价格,我们可以把全人类的财富变成一张面积 126 万平方公里的披萨,差不多相当于尼日尔的国土面积。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/pizza-niger.jpg" target="_blank" rel="noreferrer"><img src="'+q+'" alt="All the World&#39;s Wealth in Pizza"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/pizza-ground.png" target="_blank" rel="noreferrer"><img src="'+$+'" alt="eating huge pizza"></a></p><p>好吧好吧,我猜你还需要点水。按波兰泉 (Poland Spring) 16.9 盎司一瓶 1 美元的价格,我可以把全世界的财富变成一瓶 31.8 万亿加仑的水,瓶子高 11.6 公里,略高于飞机的飞行高度。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/poland-spring.jpg" target="_blank" rel="noreferrer"><img src="'+D+'" alt="Huge water bottle"></a></strong></p><p>很遗憾你陷入了这种境地,但我实在也帮不上更多忙了。作为收尾,我要把全世界 241 万亿美元的财富全部换成陆龟。</p><p>为了协助我完成计算,我请来了我养了九年的宠物陆龟兼密友——温斯顿 (Winston)。</p><p>在温斯顿极不情愿的配合下,我用卷尺量出了他的尺寸——大约 25 厘米长、15 厘米宽、13 厘米高。他当初的售价是 200 美元,所以陆龟的市场价是每立方厘米 0.20 美元。</p><p>按这个价格,我们可以把全世界的财富换成一只 2.7 公里长的陆龟。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/03/Winston.jpg" target="_blank" rel="noreferrer"><img src="'+R+'" alt="Largest Tortoise in the World"></a></strong></p><p><strong>如果你喜欢这篇,你大概也会喜欢:</strong></p><p><strong><a href="https://waitbutwhy.com/2015/03/7-3-billion-people-one-building.html" target="_blank" rel="noreferrer">把 73 亿人塞进一栋楼里</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/12/what-makes-you-you.html" target="_blank" rel="noreferrer">是什么让你成为你?</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/03/why-is-my-laptop-on.html" target="_blank" rel="noreferrer">我的笔记本电脑为什么开着?</a></strong></p><p><a href="https://waitbutwhy.com/2014/11/from-1-to-1000000.html" target="_blank" rel="noreferrer"><br></a><strong>参考资料</strong></p><ol><li><a href="https://publications.credit-suisse.com/tasks/render/file/?fileID=BCDB1364-A105-0560-1332EC9100FF5C83" target="_blank" rel="noreferrer">全球财富报告,瑞士信贷,2013 年 10 月。</a></li><li><a href="https://forms.thomsonreuters.com/GS13_UPDATE2/" target="_blank" rel="noreferrer">路透社 GFMS 新闻稿 —— 黄金调查 2013。</a></li><li><a href="http://www.forbes.com/sites/abrambrown/2014/03/03/forbes-billionaires-full-list-of-the-worlds-500-richest-people/" target="_blank" rel="noreferrer">福布斯亿万富翁:全球最富 500 人完整名单。</a></li><li><a href="http://www.census.gov/compendia/statab/2012/tables/12s0717.pdf" target="_blank" rel="noreferrer">http://www.census.gov/compendia/statab/2012/tables/12s0717.pdf</a></li><li><a href="http://www.joshuakennon.com/how-much-money-does-it-take-to-be-in-the-top-1-of-wealth-and-net-worth-in-the-united-states/" target="_blank" rel="noreferrer">http://www.joshuakennon.com/how-much-money-does-it-take-to-be-in-the-top-1-of-wealth-and-net-worth-in-the-united-states/</a></li><li><a href="http://templatelab.com/working-for-the-few-research/" target="_blank" rel="noreferrer">乐施会简报 —— 为少数人服务</a></li><li>联合国 —— <a href="http://repositories.cdlib.org/cgi/viewcontent.cgi?article=1068&amp;context=cgirs" target="_blank" rel="noreferrer">全球家庭财富分布 </a>8. 联合国儿童基金会 —— <a href="http://www.unicef.org/socialpolicy/files/Global_Inequality.pdf" target="_blank" rel="noreferrer">全球不平等:超越底层十亿</a></li><li><a href="http://data.worldbank.org/indicator/PA.NUS.PPP" target="_blank" rel="noreferrer">http://data.worldbank.org/indicator/PA.NUS.PPP</a></li></ol><hr><p>如果你喜欢 Wait But Why,可以订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/03/combined-wealth-world.html&amp;description=What%20Could%20You%20Buy%20With%20$241%20Trillion?" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p>',90)])])}const V=e(Z,[["render",E]]);export{O as __pageData,V as default};
